101	export function createXai(options: XaiProviderSettings = {}): XaiProvider {
102	  const baseURL = withoutTrailingSlash(
103	    options.baseURL ?? 'https://api.x.ai/v1',
104	  );
105	  const getHeaders = () =>
106	    withUserAgentSuffix(
107	      {
108	        Authorization: `Bearer ${loadApiKey({
109	          apiKey: options.apiKey,
110	          environmentVariableName: 'XAI_API_KEY',
111	          description: 'xAI API key',
112	        })}`,
113	        ...options.headers,
114	      },
115	      `ai-sdk/xai/${VERSION}`,
116	    );
117	
118	  const createChatLanguageModel = (modelId: XaiChatModelId) => {
119	    return new XaiChatLanguageModel(modelId, {
120	      provider: 'xai.chat',
121	      baseURL,
122	      headers: getHeaders,
123	      generateId,
124	      fetch: options.fetch,
125	    });
126	  };
127	
128	  const createResponsesLanguageModel = (modelId: XaiResponsesModelId) => {
129	    return new XaiResponsesLanguageModel(modelId, {
130	      provider: 'xai.responses',
131	      baseURL,
132	      headers: getHeaders,
133	      generateId,
134	      fetch: options.fetch,
135	    });
136	  };
137	
138	  const createImageModel = (modelId: XaiImageModelId) => {
139	    return new XaiImageModel(modelId, {
140	      provider: 'xai.image',
141	      baseURL,
142	      headers: getHeaders,
143	      fetch: options.fetch,
144	    });
145	  };
146	
147	  const createVideoModel = (modelId: XaiVideoModelId) => {
148	    return new XaiVideoModel(modelId, {
149	      provider: 'xai.video',
150	      baseURL,
151	      headers: getHeaders,
152	      fetch: options.fetch,
153	    });
154	  };
155	
156	  const provider = (modelId: XaiChatModelId) =>
157	    createChatLanguageModel(modelId);
158	
159	  provider.specificationVersion = 'v3' as const;
160	  provider.languageModel = createChatLanguageModel;
161	  provider.chat = createChatLanguageModel;
162	  provider.responses = createResponsesLanguageModel;
163	  provider.embeddingModel = (modelId: string) => {
164	    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
165	  };
166	  provider.textEmbeddingModel = provider.embeddingModel;
167	  provider.imageModel = createImageModel;
168	  provider.image = createImageModel;
169	  provider.videoModel = createVideoModel;
170	  provider.video = createVideoModel;
171	  provider.tools = xaiTools;
172	
173	  return provider;
174	}
175	
176	export const xai = createXai();
