68	/**
69	 * Provider options for xAI video generation.
70	 *
71	 * Use the `mode` option to select the operation:
72	 *
73	 * - `'edit-video'`         + `videoUrl`           -- video editing   (`POST /v1/videos/edits`)
74	 * - `'extend-video'`       + `videoUrl`           -- video extension (`POST /v1/videos/extensions`)
75	 * - `'reference-to-video'` + `referenceImageUrls` -- R2V generation  (`POST /v1/videos/generations`)
76	 * - no `mode`                                     -- standard generation from text prompts or image input
77	 *
78	 * Runtime remains backward compatible with legacy auto-detected provider
79	 * options, but the public TypeScript type is intentionally explicit so editors
80	 * can suggest valid modes and flag invalid field combinations.
81	 */
82	export type XaiVideoModelOptions =
83	  | XaiVideoGenerationOptions
84	  | XaiVideoEditModeOptions
85	  | XaiVideoExtendModeOptions
86	  | XaiVideoReferenceToVideoOptions
87	  | XaiLegacyEditVideoOptions
88	  | XaiLegacyReferenceToVideoOptions;
89	
90	// ── Runtime schemas ───────────────────────────────────────────────────
91	const baseFields = {
92	  pollIntervalMs: z.number().positive().nullish(),
93	  pollTimeoutMs: z.number().positive().nullish(),
94	  resolution: resolutionSchema.nullish(),
95	};
96	
97	const editVideoSchema = z.object({
98	  ...baseFields,
