383	export const lumaImageModelOptionsSchema = lazySchema(() =>
384	  zodSchema(
385	    z
386	      .object({
387	        /**
388	         * The type of image reference to use when providing input images.
389	         * - `image`: Guide generation using reference images (up to 4). Default.
390	         * - `style`: Apply a specific style from reference image(s).
391	         * - `character`: Create consistent characters from reference images (up to 4).
392	         * - `modify_image`: Transform a single input image with prompt guidance.
393	         */
394	        referenceType: z
395	          .enum(['image', 'style', 'character', 'modify_image'])
396	          .nullish(),
397	
398	        /**
399	         * Per-image configuration array. Each entry corresponds to an image in `prompt.images`.
400	         * Allows setting individual weights for each reference image.
401	         */
402	        images: z
403	          .array(
404	            z.object({
405	              /**
406	               * The weight of this image's influence on the generation.
407	               * - For `image`: Higher weight = closer to reference (default: 0.85)
408	               * - For `style`: Higher weight = stronger style influence (default: 0.8)
409	               * - For `modify_image`: Higher weight = closer to input, lower = more creative (default: 1.0)
410	               */
411	              weight: z.number().min(0).max(1).nullish(),
412	
413	              /**
414	               * The identity name for character references.
415	               * Used with `character` to specify which identity group the image belongs to.
416	               * Luma supports multiple identities (e.g., 'identity0', 'identity1') for generating
417	               * images with multiple consistent characters.
418	               * Default: 'identity0'
419	               */
420	              id: z.string().nullish(),
421	            }),
422	          )
423	          .nullish(),
424	
425	        /**
426	         * Override the polling interval in milliseconds (default 500).
427	         */
428	        pollIntervalMillis: z.number().nullish(),
429	
430	        /**
431	         * Override the maximum number of polling attempts (default 120).
432	         */
433	        maxPollAttempts: z.number().nullish(),
434	      })
435	      .passthrough(),
436	  ),
437	);
