## Summary: Image Generation Providers in Vercel AI SDK

Based on my thorough exploration of the codebase, here's a complete understanding of how image generation providers work:

---

### 1. **The ImageModel Interface Definition**

The current version is **ImageModelV3** (there's also V2 for backwards compatibility). Here's the complete interface:

**File:** `/packages/provider/src/image-model/v3/image-model-v3.ts`

```typescript
export type ImageModelV3 = {
  readonly specificationVersion: 'v3';
  readonly provider: string;
  readonly modelId: string;
  readonly maxImagesPerCall: number | undefined | GetMaxImagesPerCallFunction;

  doGenerate(options: ImageModelV3CallOptions): PromiseLike<{
    images: Array<string> | Array<Uint8Array>;
    warnings: Array<SharedV3Warning>;
    providerMetadata?: ImageModelV3ProviderMetadata;
    response: {
      timestamp: Date;
      modelId: string;
      headers: Record<string, string> | undefined;
    };
    usage?: ImageModelV3Usage;
  }>;
};
```

**Call Options Type:**
```typescript
export type ImageModelV3CallOptions = {
  prompt: string | undefined;
  n: number;
  size: `${number}x${number}` | undefined;
  aspectRatio: `${number}:${number}` | undefined;
  seed: number | undefined;
  files: ImageModelV3File[] | undefined;  // for image editing/variations
  mask: ImageModelV3File | undefined;      // for inpainting
  providerOptions: SharedV3ProviderOptions;
  abortSignal?: AbortSignal;
  headers?: Record<string, string | undefined>;
};
```

**File Types:**
```typescript
export type ImageModelV3File =
  | { type: 'file'; mediaType: string; data: string | Uint8Array }
  | { type: 'url'; url: string };
```

---

### 2. **Complete Example: OpenAI Image Model Implementation**

**File:** `/packages/openai/src/image/openai-image-model.ts`

This is a full implementation of ImageModelV3. Key aspects:

```typescript
export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  constructor(
    readonly modelId: OpenAIImageModelId,
    private readonly config: OpenAIImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    files,
    mask,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    const warnings: Array<SharedV3Warning> = [];

    // Handle unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    // Handle image editing vs generation
    if (files != null) {
      // Use /images/edits endpoint with form data
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({ path: '/images/edits', modelId: this.modelId }),
        headers: combineHeaders(this.config.headers(), headers),
        formData: convertToFormData<OpenAIImageEditInput>({
          model: this.modelId,
          prompt,
          image: await Promise.all(files.map(convertFileToBlob)),
          mask: mask != null ? await fileToBlob(mask) : undefined,
          n,
          size,
          ...(providerOptions.openai ?? {}),
        }),
        failedResponseHandler: openaiFailedResponseHandler,
        successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
        abortSignal,
        fetch: this.config.fetch,
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        usage: { inputTokens, outputTokens, totalTokens },
        response: { timestamp, modelId, headers: responseHeaders },
        providerMetadata: {
          openai: {
            images: response.data.map((item, index) => ({
              revisedPrompt: item.revised_prompt,
              created: response.created,
              // ... other metadata
            })),
          },
        },
      };
    }

    // Generation without editing
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...(providerOptions.openai ?? {}),
        response_format: 'b64_json',
      },
      failedResponseHandler: openaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage: { inputTokens, outputTokens, totalTokens },
      response: { timestamp, modelId, headers: responseHeaders },
      providerMetadata: { openai: { images: [...] } },
    };
  }
}
```

---

### 3. **Provider Factory: How Image Models Are Registered**

**OpenAI Example** - `/packages/openai/src/openai-provider.ts`:

```typescript
export interface OpenAIProvider extends ProviderV3 {
  /**
   * Creates a model for image generation.
   */
  image(modelId: OpenAIImageModelId): ImageModelV3;

  /**
   * Creates a model for image generation.
   */
  imageModel(modelId: OpenAIImageModelId): ImageModelV3;
}

export function createOpenAI(
  options: OpenAIProviderSettings = {},
): OpenAIProvider {
  const baseURL = withoutTrailingSlash(...) ?? 'https://api.openai.com/v1';
  const getHeaders = () => withUserAgentSuffix({ Authorization: ..., ...options.headers }, ...);

  const createImageModel = (modelId: OpenAIImageModelId) =>
    new OpenAIImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: OpenAIResponsesModelId) {
    return createLanguageModel(modelId);
  };

  // Register image methods
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as OpenAIProvider;
}
```

**Google Example** - `/packages/google/src/google-provider.ts`:

```typescript
