export class GoogleGenerativeAIImageModel implements ImageModelV3 {
  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    if (isGeminiModel(this.modelId)) {
      return this.doGenerateGemini(options);
    }
    return this.doGenerateImagen(options);
  }

  private async doGenerateImagen(options: ...): Promise<...> {
    const { responseHeaders, value: response } = await postJsonToApi<{
      predictions: Array<{ bytesBase64Encoded: string }>;
    }>({
      url: `${this.config.baseURL}/models/${this.modelId}:predict`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        instances: [{ prompt }],
        parameters: { sampleCount: n, aspectRatio, ...googleOptions },
      },
      failedResponseHandler: googleFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(googleImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.predictions.map(p => p.bytesBase64Encoded),
      warnings,
      providerMetadata: { google: { images: [...] } },
      response: { timestamp, modelId, headers: responseHeaders },
    };
  }

  private async doGenerateGemini(options: ...): Promise<...> {
    // Delegates to language model with IMAGE response modality
    const languageModel = new GoogleGenerativeAILanguageModel(this.modelId, {...});
    const result = await languageModel.doGenerate({
      prompt: languageModelPrompt,
      providerOptions: {
        google: {
          responseModalities: ['IMAGE'],
          imageConfig: { aspectRatio },
        },
      },
    });

    // Extract images from language model response
    const images: string[] = [];
    for (const part of result.content) {
      if (part.type === 'file' && part.mediaType.startsWith('image/')) {
        images.push(convertToBase64(part.data));
      }
    }

    return { images, warnings, providerMetadata, response, usage };
  }
}
