import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art cat';

// Helper to create base64-encoded image data for test responses
const testImageBase64 = btoa('test-image-binary-content');

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ 'api-key': 'test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/generate': {
      response: {
        type: 'json-value',
        body: {
          images: [{ b64_json: testImageBase64 }],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('should pass the correct parameters including size', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'pixel', pixelDensity: 2 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
        n: 1,
        size: '512x512',
        style: 'pixel',
        pixel_density: 2,
      });
    });

    it('should call the correct url', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        providerOptions: {},
        aspectRatio: undefined,
        seed: undefined,
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/generate',
      );
    });

    it('should pass headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          'Custom-Provider-Header': 'provider-header-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/generate'].response = {
        type: 'error',
        status: 400,
        body: 'Bad Request',
      };

      const model = createBasicModel();
      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Bad Request',
        statusCode: 400,
        url: 'https://api.example.com/generate',
        requestBodyValues: {
          prompt: 'A cute pixel art cat',
        },
        responseBody: 'Bad Request',
      });
    });

    it('should only send style when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'retro' },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
        n: 1,
        style: 'retro',
      });
    });

    it('should only send pixelDensity when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { pixelDensity: 3 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
        n: 1,
        pixel_density: 3,
      });
    });

    it('should send minimal body when no optional params provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: undefined,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
      });
    });

    describe('warnings', () => {
      it('should return warning for unsupported aspectRatio', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toStrictEqual([
          {
            type: 'unsupported',
            feature: 'aspectRatio',
            details:
              'This model does not support the `aspectRatio` option. Use `size` instead.',
          },
        ]);
      });

      it('should return warning for unsupported seed', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: 123,
          providerOptions: {},
        });

        expect(result.warnings).toStrictEqual([
          {
            type: 'unsupported',
            feature: 'seed',
            details: 'This model does not support the `seed` option.',
          },
        ]);
      });

      it('should return warnings for both aspectRatio and seed', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: '1:1',
          seed: 42,
          providerOptions: {},
        });

        expect(result.warnings).toStrictEqual([
          {
            type: 'unsupported',
            feature: 'aspectRatio',
            details:
              'This model does not support the `aspectRatio` option. Use `size` instead.',
          },
          {
            type: 'unsupported',
            feature: 'seed',
            details: 'This model does not support the `seed` option.',
          },
        ]);
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixelart-v1',
          headers: expect.any(Object),
        });
      });
    });

    describe('image decoding', () => {
      it('should decode base64 images to Uint8Array', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.images).toHaveLength(1);
        expect(result.images[0]).toBeInstanceOf(Uint8Array);
        // Verify the decoded content matches
        const decoded = new TextDecoder().decode(result.images[0]);
        expect(decoded).toBe('test-image-binary-content');
      });

      it('should handle multiple images in response', async () => {
        server.urls['https://api.example.com/generate'].response = {
          type: 'json-value',
          body: {
            images: [
              { b64_json: btoa('image-1') },
              { b64_json: btoa('image-2') },
            ],
          },
        };

        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 2,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.images).toHaveLength(2);
        expect(new TextDecoder().decode(result.images[0])).toBe('image-1');
        expect(new TextDecoder().decode(result.images[1])).toBe('image-2');
      });
    });
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });
});

